const dealId = $('Webhook').first().json["body"]["meta"]["entity_id"];
const campos = $('Edit Fields').first().json.data.slice(42);
const valoresWebhook = $('Webhook').first().json.body.data.custom_fields;
const resultado = {};

for (const campo of campos) {
  const key = campo.key;
  const tipo = campo.field_type;
  const valorCampo = valoresWebhook[key];

  let valorFinal = "";
  let idValorFinal = null;

  if (valorCampo != null) {
    if (tipo === "enum" && Array.isArray(campo.options)) {
      const idSelecionado = valorCampo.id ?? valorCampo;
      const opcao = campo.options.find(opt => opt.id === idSelecionado);
      valorFinal = opcao ? opcao.label : "";
      idValorFinal = opcao ? opcao.id : null;

    } else if (tipo === "set" && Array.isArray(campo.options)) {
      const idsSelecionados = valorCampo.values?.map(v => v.id) ?? [];
      const opcoesSelecionadas = campo.options.filter(opt => idsSelecionados.includes(opt.id));
      valorFinal = opcoesSelecionadas.map(opt => opt.label).join(', ');
      idValorFinal = idsSelecionados;

    } else if (tipo === "user") {
      const idUser = valorCampo.id ?? valorCampo.value ?? valorCampo;

      // Tenta buscar o nome no campo.options (se vier de Edit Fields)
      const usuario = campo.options?.find(opt => opt.id === idUser);
      valorFinal = usuario?.label ?? "";
      idValorFinal = idUser;

    } else {
      valorFinal = valorCampo?.value ?? valorCampo ?? "";
    }
  }

  resultado[key] = {
    field_type: tipo,
    name: campo.name,
    valueLabel: valorFinal,
    valueId: idValorFinal,
    options: campo.options || null
  };
}

return [{
  json: {
    dealId,
    resultado
  }
}];

const dealJson = $('Webhook').first().json;
const dealId = dealJson.id;
const campos = $('Edit Fields').first().json.data;

const resultado = {};

for (const campo of campos) {
  const key = campo.key;
  const tipo = campo.field_type;

  // Considera apenas campos customizados (hash de 40 caracteres)
  const isCustomField = /^[a-f0-9]{40}$/i.test(key);
  if (!isCustomField) continue;

  const valorCampo = dealJson[key];

  let valorFinal = "";
  let idValorFinal = null;

  if (valorCampo !== null && valorCampo !== undefined) {
    if (tipo === "set" && Array.isArray(valorCampo.values)) {
      const ids = valorCampo.values.map(v => v.id);
      const labels = campo.options
        .filter(opt => ids.includes(opt.id))
        .map(opt => opt.label);
      valorFinal = labels.join(", ");
      idValorFinal = ids;
    } else if (tipo === "enum" && Array.isArray(campo.options)) {
      const idSelecionado = valorCampo?.id ?? valorCampo;
      const opcao = campo.options.find(opt => opt.id.toString() === idSelecionado);
      valorFinal = opcao?.label ?? "";
      idValorFinal = opcao?.id ?? null;
    } else if (tipo === "user" && typeof valorCampo === "object" && valorCampo.name && valorCampo.id) {
      // Tratamento especial para campos do tipo "user"
      valorFinal = valorCampo.name;
      idValorFinal = valorCampo.id;
    } else {
      valorFinal = valorCampo?.value ?? valorCampo ?? "";
    }
  }

  resultado[key] = {
    field_type: tipo,
    name: campo.name,
    valueLabel: valorFinal,
    valueId: idValorFinal,
    options: campo.options || null
  };

  // Campo _currency associado, se existir
  const chaveMoeda = `${key}_currency`;
  if (dealJson.hasOwnProperty(chaveMoeda)) {
    resultado[chaveMoeda] = {
      field_type: "varchar",
      name: `Currency of ${campo.name}`,
      valueLabel: dealJson[chaveMoeda],
      valueId: null,
      options: null
    };
  }
}

return [{
  json: {
    dealId: dealId.toString(),
    resultado
  }
}];

